async function main() {
  console.log('🚀 Bắt đầu seed YLE Starters vocabulary (500 từ / 25 bài)...\n');

  // Tìm program Starters
  const program = await prisma.program.findFirst({
    where: { code: { contains: 'starters' } },
    include: { lessons: { orderBy: { orderIndex: 'asc' } } }
  });

  if (!program) {
    console.error('❌ Không tìm thấy program Starters! Kiểm tra lại database.');
    return;
  }

  console.log(`✅ Program: ${program.name}`);
  console.log(`   Số bài: ${program.lessons.length}\n`);

  // Map orderIndex → lessonId (bỏ qua lesson 9999)
  const lessonMap = {};
  program.lessons.forEach(l => {
    if (l.orderIndex !== 9999) lessonMap[l.orderIndex] = l.id;
  });

  // Kiểm tra đủ 25 bài không
  const missingLessons = [];
  for (let i = 1; i <= 25; i++) {
    if (!lessonMap[i]) missingLessons.push(i);
  }
  if (missingLessons.length > 0) {
    console.warn(`⚠️  Thiếu lesson: ${missingLessons.join(', ')}`);
    console.warn('   Script sẽ bỏ qua các bài này.\n');
  }

  // Xóa THEORY cũ của 25 bài (không đụng lesson 9999)
  const lessonIds = Object.values(lessonMap);
  const deleted = await prisma.lessonContent.deleteMany({
    where: { lessonId: { in: lessonIds }, contentType: 'THEORY' }
  });
  console.log(`🗑️  Đã xóa ${deleted.count} THEORY cũ\n`);
  console.log(`📝 Đang seed ${VOCAB_DATA.length} từ vựng...\n`);

  // Seed từng từ
  let ok = 0, fail = 0;
  for (const v of VOCAB_DATA) {
    const lessonId = lessonMap[v.lesson];
    if (!lessonId) { fail++; continue; }
    try {
      await prisma.lessonContent.create({
        data: {
          lessonId,
          contentType: 'THEORY',
          content: JSON.stringify({
            word: v.word,
            ipa: v.ipa,
            meaning: v.meaning,
            example_en: v.example_en,
            example_vi: v.example_vi,
            type: v.type
          })
        }
      });
      ok++;
    } catch(e) {
      console.error(`❌ "${v.word}": ${e.message}`);
      fail++;
    }
  }

  // Tổng kết
  console.log('\n========== KẾT QUẢ ==========');
  console.log(`✅ Thành công : ${ok} từ`);
  console.log(`❌ Thất bại  : ${fail} từ`);
  console.log(`📚 Tổng cộng : ${VOCAB_DATA.length} từ`);
  if (ok === 500) {
    console.log('\n🎉 Hoàn thành! 500 từ đã được seed vào database.');
  } else {
    console.log('\n⚠️  Chưa đủ 500 từ, kiểm tra lỗi phía trên.');
  }
}

main().finally(() => prisma.$disconnect());
